import{_ as e,o as a,c as o,a2 as s}from"./chunks/framework.Crpw6aS5.js";const n="/assets/01-gt71-mb-overview.B12Fl7Ml.png",i="/assets/02-gt71-mb-swd-header.DKM6A_DK.png",d="/assets/03-gt71-mb-fwk-pads.BISG0TT0.png",r="/assets/04-gt71-mb-uart-wiring.DbVKNHk8.png",l="/assets/05-nt71-mb-gps-board.CNxO4ixI.png",w=JSON.parse('{"title":"Extracting Data from a Concox GT710 GPS Tracker (Without Windows)","description":"Imported note — UART metadata extraction, PCB map, and macOS paths to a full firmware clone","frontmatter":{"title":"Extracting Data from a Concox GT710 GPS Tracker (Without Windows)","description":"Imported note — UART metadata extraction, PCB map, and macOS paths to a full firmware clone"},"headers":[],"relativePath":"obd2/vehicle-tracking/concox-gt710-firmware-extraction.md","filePath":"obd2/vehicle-tracking/concox-gt710-firmware-extraction.md"}'),c={name:"obd2/vehicle-tracking/concox-gt710-firmware-extraction.md"};function h(p,t,g,m,k,u){return a(),o("div",null,[...t[0]||(t[0]=[s(`<h1 id="extracting-data-from-a-concox-gt710-gps-tracker-without-windows" tabindex="-1">Extracting Data from a Concox GT710 GPS Tracker (Without Windows) <a class="header-anchor" href="#extracting-data-from-a-concox-gt710-gps-tracker-without-windows" aria-label="Permalink to &quot;Extracting Data from a Concox GT710 GPS Tracker (Without Windows)&quot;">​</a></h1><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: text</li><li>Origin: user-provided notes (Cursor session + <code>esp32-lilypi-door-relay/docs/concox-gt710-firmware-extraction.md</code>)</li><li>Imported: 2026-06-23</li><li>Images: 5 PCB photos saved under <code>assets/concox-gt710-firmware-extraction/</code></li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><p><em>How I went from garbled serial output to a full hardware map — and what it actually takes to back up one of these trackers on macOS.</em></p><hr><h3 id="what-i-was-trying-to-do" tabindex="-1">What I was trying to do <a class="header-anchor" href="#what-i-was-trying-to-do" aria-label="Permalink to &quot;What I was trying to do&quot;">​</a></h3><p>I had a small cellular GPS tracker connected to my Mac through a CP2102 USB‑UART adapter (<code>/dev/cu.SLAB_USBtoUART</code>). The goal was simple on paper: <strong>read the firmware</strong> — or at least understand exactly what was running on the device.</p><p>What I had was <strong>not</strong> an ESP32 dev board. It was a <strong>Concox / Jimi IoT GT710</strong> asset tracker: a waterproof GPS unit with a GSM modem, a test SIM, and almost no public documentation on how to pull its flash over the wire.</p><p>This is the story of how I figured out what I was looking at, extracted everything the UART would give me, mapped the PCB, and planned a full clone — all on <strong>macOS</strong>, without the Windows-only tools the forums usually assume you have.</p><hr><h3 id="act-1-garbled-serial-and-the-wrong-mental-model" tabindex="-1">Act 1: Garbled serial and the wrong mental model <a class="header-anchor" href="#act-1-garbled-serial-and-the-wrong-mental-model" aria-label="Permalink to &quot;Act 1: Garbled serial and the wrong mental model&quot;">​</a></h3><p>I started with PlatformIO&#39;s device monitor at <strong>115200 8-N-1</strong>. The output looked broken:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>F1: 0000 0000</span></span>
<span class="line"><span>G0: 0002 0000 [0000]</span></span>
<span class="line"><span>BL</span></span>
<span class="line"><span>er on</span></span>
<span class="line"><span>ect:GT710</span></span>
<span class="line"><span>o SIM</span></span>
<span class="line"><span>T+CMGL=0</span></span>
<span class="line"><span>OK</span></span>
<span class="line"><span>+CREG: 0,3</span></span></code></pre></div><p>My first question was whether the baud rate was wrong.</p><p><strong>It wasn&#39;t.</strong> 115200 is correct for this interface. The garble came from two things mixed on one line:</p><ol><li><strong>Boot / binary noise</strong> at power-on (<code>F1:</code>, <code>G0:</code>, <code>BL</code>)</li><li><strong>AT command traffic</strong> from the device talking to its own internal modem (<code>AT+CMGL</code>, <code>+CREG</code>, fragments of <code>No SIM</code>)</li></ol><p>The giveaway was readable cellular protocol debris: <code>T+CMGL=0</code> is almost certainly <code>AT+CMGL=0</code> (list SMS messages), and <code>ect:GT710</code> is part of a connect string for a <strong>GT710</strong> module.</p><p>So: wrong device class in my head, right baud rate on the wire.</p><hr><h3 id="act-2-talking-to-the-modem" tabindex="-1">Act 2: Talking to the modem <a class="header-anchor" href="#act-2-talking-to-the-modem" aria-label="Permalink to &quot;Act 2: Talking to the modem&quot;">​</a></h3><p>Once I closed the serial monitor so nothing else held the port, I probed the device with Python and <code>pyserial</code>.</p><p>At <strong>115200</strong> on <code>/dev/cu.SLAB_USBtoUART</code>, sending <code>AT</code> eventually returned clean responses. The device is a <strong>MediaTek modem</strong> running the MAUI stack:</p><table tabindex="0"><thead><tr><th>Command</th><th>Response</th></tr></thead><tbody><tr><td><code>ATI</code></td><td><code>MTK2</code> / <code>MAUI.11C.W14.18.IOT.MP.SP.V1.</code></td></tr><tr><td><code>AT+CGMI</code></td><td><code>MTK1</code></td></tr><tr><td><code>AT+CGMM</code></td><td><code>MTK2</code></td></tr><tr><td><code>AT+CGMR</code></td><td><code>MAUI.11C.W14.18.IOT.MP.SP.V1.F6, 2020/09/17 16:13</code></td></tr><tr><td><code>AT+CGSN</code></td><td><code>351777095470561</code> (IMEI)</td></tr><tr><td><code>AT+ICCID</code></td><td><code>89882390001250872505</code></td></tr><tr><td><code>AT+CPIN?</code></td><td><code>READY</code></td></tr><tr><td><code>AT+CREG?</code></td><td><code>0,3</code> (searching, not registered)</td></tr><tr><td><code>AT+CSQ</code></td><td><code>16, 99</code> (~−81 dBm)</td></tr></tbody></table><p>The IMSI (<code>90128…</code>) pointed at a <strong>test SIM</strong> — which explained why the modem never registered on a real network.</p><h4 id="what-this-is-and-isn-t" tabindex="-1">What this is (and isn&#39;t) <a class="header-anchor" href="#what-this-is-and-isn-t" aria-label="Permalink to &quot;What this is (and isn&#39;t)&quot;">​</a></h4><p>This is <strong>firmware identification</strong>: build strings, IMEI, SIM details, signal state. It is <strong>not</strong> a binary image of the flash. Standard AT commands don&#39;t offer &quot;dump entire chip to file.&quot;</p><p>I confirmed that the hard way:</p><table tabindex="0"><thead><tr><th>Command</th><th>Result</th></tr></thead><tbody><tr><td><code>AT+EDUMP</code></td><td><code>ERROR</code></td></tr><tr><td><code>AT+EMEMDUMP?</code></td><td><code>ERROR</code></td></tr><tr><td><code>AT+GTPKGVER?</code></td><td><code>ERROR</code></td></tr><tr><td>Concox <code>VERSION#</code> over serial</td><td>No response (SMS-only on this unit)</td></tr></tbody></table><p>One probe (<code>AT+EPON?</code>) even tripped a modem shutdown: <code>Delay time out! Shutdown...</code> — a reminder that engineering commands on production firmware are hit-or-miss.</p><hr><h3 id="act-3-automating-what-works" tabindex="-1">Act 3: Automating what works <a class="header-anchor" href="#act-3-automating-what-works" aria-label="Permalink to &quot;Act 3: Automating what works&quot;">​</a></h3><p>The useful part — querying identification over UART — deserved a script, not ad-hoc Python in a shell.</p><p>Probe script (<code>scripts/gt710_probe.py</code> in the working repo):</p><ul><li>Opens the serial port at 115200</li><li>Sends standard AT commands with gaps (the GT710 polls its own modem; rushing commands causes collisions)</li><li>Parses modem firmware, IMEI, ICCID, SIM status, registration, signal</li><li>Writes JSON to <code>gt710/device-info.json</code></li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/gt710_probe.py</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/gt710_probe.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/cu.SLAB_USBtoUART</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gt710/device-info.json</span></span></code></pre></div><p><strong>Lesson:</strong> intermittent responses aren&#39;t always &quot;wrong baud.&quot; This device runs its own AT loop. Leave the port free, power-cycle if the modem shut down, and space commands ~1.5 seconds apart.</p><hr><h3 id="act-4-opening-the-case-—-two-boards-three-firmware-stores" tabindex="-1">Act 4: Opening the case — two boards, three firmware stores <a class="header-anchor" href="#act-4-opening-the-case-—-two-boards-three-firmware-stores" aria-label="Permalink to &quot;Act 4: Opening the case — two boards, three firmware stores&quot;">​</a></h3><p>Photos of the PCB changed the picture again. The GT710 isn&#39;t one chip; it&#39;s a <strong>two-board stack</strong>:</p><h4 id="main-board-—-gt71-mb-v1-0-0" tabindex="-1">Main board — <code>GT71-MB-V1.0.0</code> <a class="header-anchor" href="#main-board-—-gt71-mb-v1-0-0" aria-label="Permalink to &quot;Main board — \`GT71-MB-V1.0.0\`&quot;">​</a></h4><p><img src="`+n+'" alt="GT71 main board overview — SIM slot, MTK shield, SWD header, and power connector"></p><p><em>Main board (<code>GT71-MB-V1.0.0</code>): MediaTek modem under the large shield, SIM slot, and the SWD header (<code>GND · RST · SWD · SWC · +3V</code>) along the top edge.</em></p><ul><li>Large metal shield → <strong>MediaTek cellular modem / baseband</strong> (where <code>MAUI.11C…</code> lives)</li><li>SIM slot, power connector, electrolytic caps</li><li><strong>SWD header:</strong> <code>GND · RST · SWD · SWC · +3V</code></li><li><strong>Near SIM:</strong> <code>RST · TX · FWK · GND</code></li><li><strong>Bottom UART:</strong> <code>TXD · RXD · GND</code> ← CP2102 wires (modem AT console)</li></ul><p><img src="'+i+'" alt="GT71 SWD debug header and pads near the SIM slot"></p><p><em>SWD header (top) and debug pads near the SIM — target for a Black Magic Probe dump of the application MCU.</em></p><p><img src="'+d+'" alt="GT71 FWK and RSTB pads used for MTK download mode"></p><p><em><code>RSTB</code>, <code>FWK</code>, and <code>GND</code> pads beside the SIM — short <strong>FWK → GND</strong> during power-on to enter MTK BROM/download mode for mtkclient.</em></p><p><img src="'+r+'" alt="CP2102 UART wires soldered to the GT71 TXD and RXD pads"></p><p><em>Modem AT console wiring: white and black wires on the bottom <code>TXD</code> / <code>RXD</code> pads — connection that returned <code>AT+CGMR</code> at 115200.</em></p><h4 id="gps-daughter-board-—-nt71-mb-v1-0" tabindex="-1">GPS daughter board — <code>NT71-MB-V1.0</code> <a class="header-anchor" href="#gps-daughter-board-—-nt71-mb-v1-0" aria-label="Permalink to &quot;GPS daughter board — `NT71-MB-V1.0`&quot;">​</a></h4><p><img src="'+l+`" alt="NT71 GPS daughter board with ceramic antenna and NT71-MAIN module"></p><p><em>GPS daughter board (<code>NT71-MB-V1.0</code>): shielded <strong>NT71-MAIN</strong> module, ceramic GPS antenna (<code>CUJXGB11</code>), and UART pads along the bottom edge.</em></p><ul><li>Shielded module labelled <strong>NT71-MAIN</strong> (<code>WFCP200930002A</code>, <code>HF201030</code>)</li><li>Ceramic GPS antenna (<code>CUJXGB11</code>)</li><li><strong>UART pads:</strong> <code>VBAT · GND · RXD1 · TXD1 · BST_EN · TXD3 · RXD3 · …</code></li></ul><p>A <strong>complete backup</strong> means three targets:</p><table tabindex="0"><thead><tr><th>Target</th><th>Location</th><th>Likely tool</th></tr></thead><tbody><tr><td>MTK modem + integrated flash</td><td>Under shield on <code>GT71-MB</code></td><td><strong>mtkclient</strong> over UART + boot strap</td></tr><tr><td>Application MCU</td><td><code>GT71-MB</code> SWD pads</td><td><strong>Black Magic Probe</strong> (e.g. WeAct Black Pill F411)</td></tr><tr><td>NT71 GPS / app module</td><td><code>NT71-MB</code> UART + <code>BST_EN</code></td><td>UART bootloader or mtkclient</td></tr></tbody></table><p>No single cable gets everything.</p><hr><h3 id="act-5-you-don-t-need-windows" tabindex="-1">Act 5: You don&#39;t need Windows <a class="header-anchor" href="#act-5-you-don-t-need-windows" aria-label="Permalink to &quot;Act 5: You don&#39;t need Windows&quot;">​</a></h3><p>Forum threads for MediaTek often assume <strong>Modem META</strong> or <strong>SP Flash Tool</strong> on Windows. The good news on macOS:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Platform</th><th>Role</th></tr></thead><tbody><tr><td><a href="https://github.com/bkerler/mtkclient" target="_blank" rel="noreferrer">mtkclient</a></td><td>macOS, Linux, Windows</td><td>Full flash read on <strong>MT6261-class IoT</strong> chips: <code>python mtk.py rf flash.bin --iot</code></td></tr><tr><td>Black Magic Probe</td><td>macOS via <code>blackmagic</code> / OpenOCD</td><td>SWD dump of application MCU</td></tr><tr><td><code>gt710_probe.py</code></td><td>macOS</td><td>Metadata over AT (completed step)</td></tr></tbody></table><h4 id="mtkclient-on-macos-modem-main-flash" tabindex="-1">mtkclient on macOS (modem / main flash) <a class="header-anchor" href="#mtkclient-on-macos-modem-main-flash" aria-label="Permalink to &quot;mtkclient on macOS (modem / main flash)&quot;">​</a></h4><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> macfuse</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openssl</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/bkerler/mtkclient</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mtkclient</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> venv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> venv</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> venv/bin/activate</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> requirements.txt</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Enter download mode first (see below), then:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mtk.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> printgpt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --iot</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --serialport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/cu.SLAB_USBtoUART</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --debugmode</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mtk.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gt710-mtk-full.bin</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --iot</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --serialport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/cu.SLAB_USBtoUART</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --debugmode</span></span></code></pre></div><p><strong>Entering BROM / download mode</strong> — try in order:</p><ol><li>Power off → short <strong>FWK → GND</strong> → apply power → run mtkclient → release when connected</li><li>Power off → hold <strong>RST</strong> low during power-on</li><li>Under the large shield: classic MTK test point (<strong>KCOL0 / COLO</strong>) shorted to <strong>GND</strong> during power-on</li></ol><h4 id="swd-with-a-weact-black-pill-f411-v2-0" tabindex="-1">SWD with a WeAct Black Pill F411 (V2.0) <a class="header-anchor" href="#swd-with-a-weact-black-pill-f411-v2-0" aria-label="Permalink to &quot;SWD with a WeAct Black Pill F411 (V2.0)&quot;">​</a></h4><p>Flashed as <strong>Black Magic Probe</strong> (<code>blackpill-f411ce</code>):</p><table tabindex="0"><thead><tr><th>BMP (target side)</th><th>GT71-MB pad</th></tr></thead><tbody><tr><td>GND</td><td>GND</td></tr><tr><td>PB9 (SWDIO)</td><td>SWD</td></tr><tr><td>PB8 (SWCLK)</td><td>SWC</td></tr><tr><td>PA5 (nRST)</td><td>RST (optional)</td></tr></tbody></table><p>Leave <strong>+3V</strong> disconnected if the tracker is already powered from its own connector.</p><h4 id="bench-hardware-verdict" tabindex="-1">Bench hardware verdict <a class="header-anchor" href="#bench-hardware-verdict" aria-label="Permalink to &quot;Bench hardware verdict&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Board</th><th>Verdict</th></tr></thead><tbody><tr><td><strong>WeAct Black Pill F411</strong></td><td>Primary SWD probe after BMP flash</td></tr><tr><td><strong>ESP-Prog</strong></td><td>Useful as spare UART for mtkclient; SWD possible but fiddly</td></tr><tr><td><strong>Arduino Nano (ATmega328)</strong></td><td>No — no SWD, can&#39;t run BMP</td></tr></tbody></table><hr><h3 id="recommended-order-of-operations" tabindex="-1">Recommended order of operations <a class="header-anchor" href="#recommended-order-of-operations" aria-label="Permalink to &quot;Recommended order of operations&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. gt710_probe.py          → metadata JSON (done)</span></span>
<span class="line"><span>2. mtkclient + FWK strap   → gt710-mtk-full.bin</span></span>
<span class="line"><span>3. BMP on Black Pill       → gt71-app.bin via SWD</span></span>
<span class="line"><span>4. BST_EN + RXD1/TXD1      → NT71 module bootloader hunt</span></span></code></pre></div><hr><h3 id="wiring-reference-modem-uart-—-what-worked" tabindex="-1">Wiring reference (modem UART — what worked) <a class="header-anchor" href="#wiring-reference-modem-uart-—-what-worked" aria-label="Permalink to &quot;Wiring reference (modem UART — what worked)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>USB-serial RX  →  board TXD</span></span>
<span class="line"><span>USB-serial TX  →  board RXD</span></span>
<span class="line"><span>GND            →  GND</span></span></code></pre></div><p>Do <strong>not</strong> feed 5 V from the adapter if the board has its own supply.</p><hr><h3 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Extraction</th><th>State</th></tr></thead><tbody><tr><td>Modem firmware <strong>version</strong> + IMEI/ICCID/SIM</td><td>✅ Via AT / <code>gt710_probe.py</code></td></tr><tr><td>Modem <strong>binary</strong> flash</td><td>⏳ mtkclient + FWK/BROM strap</td></tr><tr><td>App MCU <strong>binary</strong></td><td>⏳ BMP + SWD on <code>GT71-MB</code></td></tr><tr><td>NT71 GPS module</td><td>⏳ UART + <code>BST_EN</code> bootloader</td></tr><tr><td>Concox app version string</td><td>⏳ SMS <code>VERSION#</code> with working SIM</td></tr></tbody></table><hr><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li><strong>115200 is correct</strong> for the GT71 modem AT UART; garbled output was boot noise plus the device polling its own modem.</li><li><strong>AT commands yield metadata only</strong> (<code>AT+CGMR</code>, IMEI, ICCID) — not a flash binary; dump commands return <code>ERROR</code>.</li><li>The GT710 is <strong>two PCBs</strong> (<code>GT71-MB</code> + <code>NT71-MB</code>) with <strong>three firmware stores</strong>; a full clone needs mtkclient, SWD, and possibly the GPS-board UART bootloader.</li><li><strong>macOS works</strong> — mtkclient (<code>--iot</code>) and Black Magic Probe on a WeAct F411 replace Windows META/SP Flash for most of the job.</li><li><strong>Five PCB photos</strong> document SWD, FWK, UART, and GPS-board pads for repeatability.</li></ul>`,84)])])}const T=e(c,[["render",h]]);export{w as __pageData,T as default};
